mapper.select:
SELECT COUNT(BOARD_SEQ) FROM NMCP_BOARD_BAS WHERE 1=1 AND BOARD_CTG_SEQ = 51 AND VIEW_YN = 'Y' AND NOTI_YN = 'N' AND BOARD_SEQ NOT IN ( SELECT BOARD_SEQ FROM ( SELECT BOARD_SEQ FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = 51 AND NOTI_YN = 'Y' AND VIEW_YN = 'Y' ORDER BY BOARD_WRITE_DT DESC, BOARD_SEQ DESC ) A WHERE ROWNUM <= 5 )
AND ( UPPER(fnHTMLtoTEXT(BOARD_SUBJECT)) LIKE '%' || UPPER('!%') || '%' || '%' ESCAPE '!' OR UPPER(fnHTMLtoTEXT(BOARD_CONTENTS)) LIKE '%' || UPPER('!%') || '%' || '%' ESCAPE '!')
AND SBST_CTG = #{sbstCtg}

SELECT BOARD_NUM, BOARD_SEQ, BOARD_CTG_SEQ, BOARD_HIT_CNT, BOARD_SUBJECT, BOARD_WRITER_NM, VIEW_YN, NOTI_YN, BOARD_WRITE_DT, BOARD_ATT_YN FROM ( SELECT ROW_NUMBER() OVER(ORDER BY BOARD_WRITE_DT, BOARD_SEQ) AS BOARD_NUM, BOARD_SEQ, BOARD_CTG_SEQ, BOARD_HIT_CNT, BOARD_SUBJECT, BOARD_WRITER_NM, VIEW_YN, NOTI_YN, TO_CHAR(BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, BOARD_ATT_YN FROM NMCP_BOARD_BAS WHERE 1=1 AND BOARD_CTG_SEQ = 51 AND VIEW_YN = 'Y' AND NOTI_YN = 'N' AND BOARD_SEQ NOT IN ( SELECT BOARD_SEQ FROM ( SELECT BOARD_SEQ FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = 51 AND NOTI_YN = 'Y' AND VIEW_YN = 'Y' ORDER BY BOARD_WRITE_DT DESC, BOARD_SEQ DESC ) A WHERE ROWNUM <= 5 )
AND (UPPER(fnHTMLtoTEXT(BOARD_SUBJECT)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR UPPER(fnHTMLtoTEXT(BOARD_CONTENTS)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')
AND SBST_CTG = #{sbstCtg}
) ORDER BY BOARD_WRITE_DT DESC, BOARD_SEQ DESC

SELECT BOARD_SEQ , BOARD_CTG_SEQ , BOARD_SUBJECT , BOARD_WRITER_NM , NOTI_YN , VIEW_YN , BOARD_WRITE_DT , BOARD_ATT_YN , CRET_DT , NEXT_SEQ , NEXT_SUBJECT , NEXT_DT , PRE_SEQ , PRE_SUBJECT , PRE_DT FROM ( SELECT BOARD_SEQ, BOARD_CTG_SEQ, BOARD_SUBJECT, BOARD_WRITER_NM, NOTI_YN, VIEW_YN, TO_CHAR(BOARD_WRITE_DT, 'YYYY.MM.DD') AS BOARD_WRITE_DT, BOARD_ATT_YN, CRET_DT, lead(BOARD_SEQ,1) over (order by BOARD_WRITE_DT, BOARD_SEQ) NEXT_SEQ, lead(BOARD_SUBJECT,1,'다음글이 없습니다.') over (order by BOARD_WRITE_DT, BOARD_SEQ) NEXT_SUBJECT, lead(CRET_DT,1,'') over (order by BOARD_WRITE_DT, BOARD_SEQ) NEXT_DT, lag(BOARD_SEQ,1) over (order by BOARD_WRITE_DT, BOARD_SEQ) PRE_SEQ, lag(BOARD_SUBJECT,1,'이전글이 없습니다.') over (order by BOARD_WRITE_DT, BOARD_SEQ) PRE_SUBJECT, lag(CRET_DT,1,'') over (order by BOARD_WRITE_DT, BOARD_SEQ) PRE_DT FROM NMCP_BOARD_BAS WHERE BOARD_CTG_SEQ = 51
AND (UPPER(fnHTMLtoTEXT(BOARD_SUBJECT)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!' OR UPPER(fnHTMLtoTEXT(BOARD_CONTENTS)) LIKE '%' || UPPER(#{searchNm}) || '%' || '%' ESCAPE '!')
AND NOTI_YN = 'N' AND VIEW_YN = 'Y' ) WHERE BOARD_SEQ = #{boardSeq}
